1. using Microsoft.ML;
2. using Microsoft.ML.Data;
3. using TicketClassifier.Models;
4. 
5. namespace TicketClassifier.Services;
6. 
7. public class TicketClassifierService
8. {
9.     private readonly MLContext _mlContext;
10.     private readonly ITransformer _model;
11.     private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
12.     private readonly EvaluationMetrics _metrics;
13.     private readonly string[] _categoryLabels;
14. 
15.     public TicketClassifierService(string dataPath)
16.     {
17.         _mlContext = new MLContext(seed: 42);
18. 
19.         var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
20.             dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);
21. 
22.         var pipeline = _mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketData.Category))
23.             .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketData.Subject)))
24.             .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketData.Description)))
25.             .Append(_mlContext.Transforms.Concatenate("Features", "SubjectFeatures", "DescriptionFeatures", nameof(TicketData.Priority)))
26.             .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
27.             .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
28.             .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));
29. 
30.         // Train/test split for evaluation
31.         var splitData = _mlContext.Data.TrainTestSplit(dataView, testFraction: 0.3);
32. 
33.         _model = pipeline.Fit(splitData.TrainSet);
34. 
35.         // Evaluate
36.         var predictions = _model.Transform(splitData.TestSet);
37.         var metrics = _mlContext.MulticlassClassification.Evaluate(predictions, "Label");
38.         _metrics = new EvaluationMetrics
39.         {
40.             MacroAccuracy = metrics.MacroAccuracy,
41.             MicroAccuracy = metrics.MicroAccuracy,
42.             LogLoss = metrics.LogLoss,
43.             LogLossReduction = metrics.LogLossReduction
44.         };
45. 
