using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly EvaluationMetrics _metrics;
    private readonly string[] _categoryLabels;

    public TicketClassifierService(string dataPath)
    {
        _mlContext = new MLContext(seed: 42);

        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var featurePipeline = _mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features", "SubjectFeatures", "DescriptionFeatures", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"));

        var trainer = _mlContext.MulticlassClassification.Trainers
            .SdcaMaximumEntropy("Label", "Features", maximumNumberOfIterations: 100);

        var pipeline = featurePipeline
            .Append(trainer)
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        // Cross-validate for metrics (works better with small datasets)
        var cvResults = _mlContext.MulticlassClassification.CrossValidate(dataView, pipeline, numberOfFolds: 3, labelColumnName: "Label");
        var avgMetrics = cvResults.Select(r => r.Metrics).ToList();
        _metrics = new EvaluationMetrics
        {
            MacroAccuracy = avgMetrics.Average(m => m.MacroAccuracy),
            MicroAccuracy = avgMetrics.Average(m => m.MicroAccuracy),
            LogLoss = avgMetrics.Average(m => m.LogLoss),
            LogLossReduction = avgMetrics.Average(m => m.LogLossReduction)
        };

        // Train on full data for production predictions
        _model = pipeline.Fit(dataView);
        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);

        // Extract label names from the model schema
        var schema = _model.GetOutputSchema(dataView.Schema);
        var labelCol = schema["Label"];
        var keyValues = new VBuffer<ReadOnlyMemory<char>>();
        labelCol.GetKeyValues(ref keyValues);
        _categoryLabels = keyValues.DenseValues().Select(v => v.ToString()).ToArray();
        if (_categoryLabels.Length == 0)
        {
            _categoryLabels = ["Billing", "General", "Technical"];
        }
    }

    public PredictionResponse Predict(TicketRequest request)
    {
        var ticketData = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
